-- ── Libre Translate ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibreTranslate is a free, open-source, self-hosted machine translation API and web app built on the Argos Translate engine.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Chinese$q$, $q$Japanese$q$, $q$Korean$q$, $q$Arabic$q$, $q$Dutch$q$, $q$Turkish$q$, $q$Ukrainian$q$, $q$Polish$q$, $q$Czech$q$, $q$Hungarian$q$, $q$Bulgarian$q$, $q$Greek$q$, $q$Hindi$q$]::text[],
  seo_title = COALESCE($q$LibreTranslate Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibreTranslate review 2026: a free, open-source, self-hosted machine translation API. See features, self-hosting steps, API pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreTranslate is a free and open-source machine translation API created by developer Piero Toffanin, who also runs the geospatial company UAV4GEO and works full time on open-source software. The project was first released around 2020 and is maintained on GitHub under the LibreTranslate organization, with an active community of contributors rather than a venture-backed company behind it. Its defining characteristic, and the reason it is frequently cited as a privacy-respecting alternative to Google Translate or Microsoft Translator, is that it does not depend on any proprietary cloud translation service. Instead, LibreTranslate is built on top of Argos Translate, an open-source Python library that uses locally-run neural machine translation models (based on the OpenNMT and Marian frameworks) to translate text entirely offline once the language models are downloaded. Because translation happens on infrastructure the operator controls, no text ever needs to leave the host server, which matters for organizations with strict data-residency, GDPR, or confidentiality requirements. The project is licensed under the GNU Affero General Public License v3.0 (AGPL-3.0), a copyleft license that requires anyone who runs a modified version of LibreTranslate as a network service to also release their source code changes, which keeps the ecosystem open even for hosted forks. Architecturally, LibreTranslate is a Python Flask application that exposes a REST API (translate, detect language, and file translation endpoints) plus a simple web UI, and it ships as a pip package, a standalone executable, or, most commonly, a Docker container. Self-hosting is straightforward: an operator pulls the official Docker image, optionally mounts a volume for the downloaded language models, and can enable features like API-key authentication, rate limiting, a suggestions endpoint for community-sourced corrections, and CORS configuration for browser-based use. Supported language pairs depend on which Argos Translate models are installed, but the project distributes dozens of language packs covering major world languages such as English, Spanish, French, German, Italian, Portuguese, Russian, Chinese, Japanese, Korean, Arabic, and many more, with translation quality that is generally regarded as solid for everyday text but behind top-tier commercial neural engines for nuanced or highly technical content. For teams that do not want to manage their own server, the LibreTranslate team also operates a hosted API through a companion portal, offering paid tiers (reported around $29 per month for a Pro tier and $58 per month for a Business tier) with higher character and request limits, while self-hosting the open-source software remains completely free and unlimited. LibreTranslate's target audience spans developers embedding translation into apps without vendor lock-in, privacy-conscious businesses and public-sector organizations that cannot send user data to third-party APIs, hobbyists running home-lab or self-hosted stacks (it appears frequently in self-hosted software directories and Docker Compose collections), and open-source projects that want a translation backend they can audit and modify. It competes primarily with commercial machine translation APIs like Google Cloud Translation, Microsoft Translator, DeepL, and Amazon Translate, as well as with other open-source or self-hostable engines such as Apertium and locally-run LLM-based translators. Its key differentiation is the combination of zero licensing cost, offline capability, and full data control, at the tradeoff of somewhat lower translation fluency compared to the largest commercial neural models and the operational burden of running and updating your own instance. Because there is no parent company, there is no funding history, headquarters, or employee count to report; the project should be described as a community-maintained open-source effort with an optional paid hosted API run by its maintainers, not a venture-funded startup.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '349b9202-524b-41fb-ba14-33f80aa672b7';

