-- ── librebooking ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibreBooking is a free, open-source resource and room scheduling system descended from the phpScheduleIt/Booked Scheduler project.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$librebooking Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$librebooking review 2026: a free, open-source resource and room booking system. Explore features, self-hosting requirements and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreBooking is an open-source resource and room scheduling application with roots going back to phpScheduleIt, a PHP-based reservation system first created around 2004. phpScheduleIt was later rebranded and expanded into Booked Scheduler, which for years was distributed with both a free open-source edition and a paid hosted edition. In 2020, after the last fully open-source release of Booked Scheduler, community members forked that codebase to create LibreBooking, ensuring the project would remain permanently free and open source rather than depend on the commercial roadmap of its predecessor. Since then, LibreBooking has been developed independently under its own GitHub organization, LibreBooking, with the develop branch carrying ongoing work and periodic stable releases (the documentation references version 5.2.0 among recent milestones). The software is licensed under the GPL-3.0 license, meaning anyone can inspect, modify, and redistribute the code as long as derivative works remain open source. Architecturally, LibreBooking is a traditional server-rendered PHP web application backed by a MySQL or MariaDB database, requiring PHP 8.2 or later, and it can be installed on a standard LAMP-style stack or deployed via Docker for simpler setup. The interface uses Bootstrap 5, giving it a responsive, mobile-friendly layout out of the box. Functionally, LibreBooking is built around the concept of reservable resources, which can represent conference rooms, equipment, vehicles, lab benches, or any other bookable asset an organization manages. Administrators can define resource groups, set reservation rules such as minimum and maximum booking durations, blackout periods, and approval workflows, and assign role-based permissions so that different user groups have different booking privileges. The system supports quota and credit-based booking limits, useful for organizations that want to cap how much resource time a given user or department can consume, and it includes reporting tools for usage analysis. For interoperability, LibreBooking can export calendar data in ICS format so reservations sync into external calendar clients like Outlook or Thunderbird, and it supports multiple authentication backends including LDAP, Active Directory, OAuth2, and SAML, which makes it straightforward to integrate into an existing organizational identity system. The project is architected to be extensible, with a plugin-oriented structure and custom theming support for organizations that want to adjust branding. There is no commercial company behind LibreBooking; it is maintained by volunteer contributors, and community support happens through Discord and GitHub Discussions rather than a paid support desk, although a public demo instance is available for organizations to evaluate the software before self-hosting it. Because there is no vendor, there is also no official managed hosting or SaaS tier, so organizations that want to use LibreBooking are expected to install and maintain it themselves, typically on their own server or a cloud VM. Its target audience includes universities, coworking spaces, libraries, labs, and any organization that needs to manage bookable rooms or shared equipment without paying for a commercial scheduling SaaS product. It competes with commercial booking platforms such as Robin, Skedda, and Calendly's resource-booking features, as well as with other open-source scheduling tools, differentiating itself primarily through being fully free, self-hostable, and free of the recurring per-seat or per-resource fees that many commercial competitors charge. The tradeoff is that adopters take on the responsibility of hosting, securing, and upgrading the application themselves, since there is no vendor-provided SLA or managed cloud offering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c907b9e7-a5f5-46c0-a8d3-cce0044adb42';

