-- ── LibreKB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibreKB is a free, open-source, self-hosted knowledge base web app built with PHP and MySQL.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LibreKB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibreKB review 2026: a free, open-source, self-hosted PHP knowledge base app. Explore features, setup requirements, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreKB is a lightweight, free, and open-source knowledge base application created by developer Michael Staake and released on GitHub in May 2024. It is a small community project rather than a company-backed product, maintained through GitHub with contributions and discussions from its user base, and it has continued to receive updates, with a version 2.0.1 release in late 2025. LibreKB is licensed under GPL-3.0, meaning the source code is fully open, free to modify, and any distributed derivative work must also remain open source. Technically, LibreKB is built as a classic PHP and MySQL web application, with the codebase roughly 91 percent PHP and the remainder CSS, which keeps it compatible with almost any standard shared-hosting environment or LAMP-style server, while also offering Docker support for containerized deployment. The design goal behind LibreKB is simplicity: rather than competing with large enterprise knowledge management suites, it aims to give individuals, small teams, and organizations a straightforward way to publish and organize help articles, internal documentation, or FAQ-style content without the licensing costs or complexity of commercial platforms like Zendesk, Document360, or Confluence. Core functionality includes a rich-text article editor powered by TinyMCE, role-based user groups so administrators can control who can create, edit, or simply read content, customizable branding so the knowledge base can be styled to match an organization's identity, and email-based password recovery for account management. The interface is built on Bootstrap, giving it a responsive layout that works across desktop and mobile browsers without a dedicated mobile app. Because the entire stack is just PHP and MySQL, setup is fast: an operator can deploy LibreKB on nearly any hosting provider that supports PHP, or spin it up quickly via Docker, without needing specialized infrastructure knowledge. There is no paid tier, subscription, or commercial edition; LibreKB is entirely free to self-host, and support is handled informally through GitHub Discussions and the project's documentation site rather than a dedicated support team. This makes LibreKB best suited for smaller organizations, solo developers, freelancers, or hobbyists who want an internal wiki or public-facing help center but do not want to pay for or maintain a heavier platform. Its competitors in the open-source knowledge base space include tools like BookStack, Wiki.js, and Outline (which has a more complex, Node-based stack), as well as commercial SaaS knowledge base products; LibreKB differentiates itself primarily through its minimalism and ease of deployment on ordinary PHP hosting, which lowers the barrier to entry compared to platforms that require Node.js, Docker orchestration, or a database beyond MySQL. The tradeoff is that LibreKB has a much smaller feature set and community than more established open-source knowledge base projects, fewer integrations, and no enterprise features like SSO or granular analytics as of its current releases, so organizations with more complex documentation needs may outgrow it. Because it is a community project with a single primary maintainer and no company structure, there is no founding company, headquarters, employee count, or funding history to report, and any enrichment content should reflect that it is a small, actively maintained open-source tool rather than a corporate product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c69e1506-7e03-4ddc-b000-d2233369bdcb';

