-- ── LibreNMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibreNMS is a free, open-source, community-maintained network monitoring system forked from Observium.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LibreNMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibreNMS review 2026: a free, open-source, GPL-licensed network monitoring system forked from Observium. See features, self-hosting and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreNMS is a fully open-source network monitoring system that was forked in 2013 from the last GPL-licensed release of Observium, another PHP and SNMP-based monitoring tool. The fork happened because the LibreNMS founders wanted the project to remain community-governed and permanently open source, in contrast to Observium's later shift toward a hybrid model where the fully-featured version required a paid license. There is no company behind LibreNMS; it is maintained as a community-based project by a distributed group of volunteer contributors on GitHub, governed collectively rather than by a single vendor, though commercial support is available from third-party partner organizations such as Config Services Ltd for organizations that want a paid support contract layered on top of the free software. The project is licensed under GPL-3.0 (or any later version), with copyright attributed to individual LibreNMS contributors dating back to the 2013 fork. Technically, LibreNMS is a PHP, MySQL, and SNMP-based application designed for autodiscovery of network infrastructure. Once pointed at a network segment or seeded with device credentials, it can automatically discover switches, routers, firewalls, servers, and other SNMP-capable hardware from vendors including Cisco, Juniper, HP, Brocade, and Foundry, as well as monitor Linux and FreeBSD hosts. It builds historical graphs of bandwidth, CPU, memory, temperature, and other metrics, and it supports distributed polling, which lets large or geographically spread networks split monitoring load across multiple polling nodes rather than relying on a single central server. Alerting is highly configurable, with support for delivery via email, IRC, Slack, and other channels, and the system exposes a comprehensive API so alerting, inventory, and graph data can be pulled into external dashboards or automation scripts. LibreNMS also includes bandwidth billing functionality, useful for ISPs or hosting providers that need to bill customers based on measured network usage, and it integrates with complementary open-source network tools like RANCID and Oxidized for configuration backup, and collectd for extended metric collection. Native mobile apps for iOS and Android, plus a mobile-friendly web interface, let network administrators check status and alerts away from a desktop. Deployment options include traditional installation on CentOS or Ubuntu behind Apache or Nginx, or Docker containers distributed via Docker Hub and Quay, with the project maintaining detailed documentation to guide either path. Because LibreNMS is entirely free and open source with no paid software tier, its total cost of ownership is limited to the infrastructure needed to run it plus, optionally, a commercial support contract from a partner organization. Its primary competitors are other network monitoring platforms, both open-source alternatives like Zabbix, Nagios, Cacti, and PRTG, and its own ancestor Observium in its now partially-closed commercial form; LibreNMS differentiates itself with strong autodiscovery, broad vendor device support out of the box, and a specifically community-first governance model that guarantees the core software will never be paywalled. Its target audience is network administrators, managed service providers, and IT teams at organizations of any size that need enterprise-grade network visibility without paying per-device or per-node licensing fees common in commercial network monitoring tools. Because LibreNMS has no company structure, there is no headquarters, employee count, or funding history to report; it should be described purely as a community open-source project with optional third-party commercial support rather than a vendor-backed product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f5945274-4119-4f53-a92b-62b5b22c5045';

