UPDATE tools SET
  short_description = COALESCE($q$LibreOffice is a free, open-source office suite developed by The Document Foundation, forked from OpenOffice.org in 2010.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Chinese$q$, $q$Japanese$q$, $q$Korean$q$, $q$Dutch$q$, $q$Polish$q$, $q$Czech$q$, $q$Hungarian$q$, $q$Arabic$q$, $q$Turkish$q$, $q$Ukrainian$q$, $q$Greek$q$, $q$Hindi$q$, $q$Swedish$q$]::text[],
  seo_title = COALESCE($q$LibreOffice Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibreOffice review 2026: the free, open-source office suite from The Document Foundation. Explore Writer, Calc, Impress, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreOffice is a free and open-source office productivity suite developed and governed by The Document Foundation (TDF), a non-profit organization established under German law in 2010 and headquartered in Berlin. Its origin traces back to a corporate schism: OpenOffice.org, itself descended from the commercial StarOffice suite that Sun Microsystems acquired from Star Division in 1999 and open-sourced, came under Oracle's control after Oracle acquired Sun in early 2010. Concerned about Oracle's stewardship of the project and its broader posture toward open-source software, the majority of OpenOffice.org's community developers left in September 2010 to form The Document Foundation as an independent, vendor-neutral home for the codebase, and announced a fork named LibreOffice the same month. The first stable LibreOffice release shipped in January 2011 and was quickly adopted as the default office suite by most major Linux distributions, effectively succeeding OpenOffice.org (whose remaining assets Oracle later donated to the Apache Software Foundation, spawning the separately maintained Apache OpenOffice). LibreOffice is dual-licensed under the Mozilla Public License v2.0 (MPL 2.0) and the GNU Lesser General Public License v3.0 or later (LGPLv3+), a structure chosen to maximize compatibility with other free-software licenses; contributors are asked to license their code jointly under both. The suite comprises six core applications: Writer (word processing), Calc (spreadsheets), Impress (presentations), Draw (vector graphics and diagramming), Base (database front-end), and Math (formula and equation editing). It uses the OpenDocument Format (ODF) as its native file format, an ISO/IEC-standardized format, while offering extensive import and export compatibility with Microsoft Office formats (.docx, .xlsx, .pptx) and many legacy and niche document formats, making it a practical drop-in replacement for Microsoft Office in most everyday use cases. LibreOffice is available for Windows, macOS, and Linux, with no license fees, activation limits, or subscription requirements at any point; downloads have exceeded 400 million as of January 2025, with roughly 1 million downloads per week, reflecting its status as one of the most widely used pieces of open-source desktop software in the world. The Document Foundation itself does not sell LibreOffice; instead it is funded through voluntary donations, and it operates a certification program for third-party professionals and companies (branded as TDF-certified developers and migration/support partners) who provide paid deployment, customization, and enterprise support services around the free core software, similar to the Red Hat model applied to office productivity. The Foundation publishes annual financial reports for transparency and coordinates release engineering, quality assurance, and localization for a project translated into dozens of languages by volunteer communities worldwide. LibreOffice's target audience is broad: individual users who want a free alternative to Microsoft Office, schools and universities operating under tight IT budgets, government agencies (several European governments have mandated ODF and LibreOffice adoption for sovereignty and cost reasons), and Linux distributions that ship it as their default office suite. Its direct competitors include Microsoft Office/Microsoft 365, Google Workspace, Apache OpenOffice (its own sibling fork), and WPS Office; LibreOffice differentiates itself through a genuinely open governance model with no single corporate owner, complete absence of licensing costs even for commercial and enterprise use, strong standards-based interoperability via ODF, and an active, transparent non-profit foundation rather than a company that could be acquired or change its licensing terms unilaterally. The main tradeoffs compared to Microsoft Office are occasional formatting fidelity issues when round-tripping complex .docx or .xlsx files, a smaller and less centralized cloud-collaboration story (though TDF partners and community projects like Collabora Online fill that gap), and a UI that some users find less polished than Microsoft's, though LibreOffice has invested heavily in modernizing its interface, including an optional ribbon-style NotebookBar layout, in recent releases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54c13dd3-4248-499f-8fcf-083dadd9d1bb';

