-- ── LibrePhotos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibrePhotos is a free, open-source, self-hosted photo management service with AI-powered face recognition and search, built as a private alternative to Google Photos.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LibrePhotos Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibrePhotos review 2026: a free, open-source, self-hosted Google Photos alternative with AI face recognition. See features, requirements and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibrePhotos is a self-hosted, open-source photo management application built as a privacy-respecting alternative to Google Photos. Its lineage traces back to a project originally called ownphotos, which was reworked and rebranded as LibrePhotos under its own GitHub organization, LibrePhotos, around 2020. It is maintained as a community open-source project with no company behind it, sustained by contributor activity, GitHub issues and discussions, and a Discord community rather than a commercial entity. The software is released under the permissive MIT License, allowing free use, modification, and redistribution with minimal restrictions. Architecturally, LibrePhotos is split into a backend and a frontend that communicate through a reverse proxy. The backend is a Django 5 REST API responsible for machine-learning pipelines and background job processing, backed by a PostgreSQL database and the Django-Q2 task queue for asynchronous work such as thumbnail generation and ML inference. The frontend is a React 18 and Vite single-page application written in TypeScript, using MapLibre GL for interactive map-based photo browsing and i18next for internationalization. The entire stack is designed to be deployed via Docker Compose, which bundles the backend, frontend, database, and supporting services into a single reproducible setup, with an Nginx layer handling routing between components. LibrePhotos's core appeal is that it replicates much of the intelligent organization users expect from Google Photos while keeping all images and metadata on infrastructure the user fully controls. Its machine-learning features include facial recognition and clustering, which groups photos of the same person automatically; scene classification powered by the Places365 model, which tags photos by location type (beach, forest, office, etc.); automatic image captioning; object detection; semantic search that lets users search photos using natural-language descriptions of their content rather than only filenames or manually applied tags; and reverse geocoding, which converts embedded GPS coordinates into readable place names so photos can be browsed by location and automatically grouped into descriptive, timeline-based albums such as a weekend trip labeled by city and date. The application supports all major photo and video formats, including RAW camera formats and HEIC/HEIF from iPhones, and provides multi-user support so a household or small team can share a single LibrePhotos instance with separate libraries and permissions. Because the machine-learning pipelines run locally rather than calling a cloud AI API, hardware requirements are more substantial than a typical web app: the project recommends at least 8 GB of RAM for smooth operation of the ML features, with a bare minimum of around 4 GB, along with at least 10 GB of disk space for the Docker images and machine-learning models before accounting for the photo library itself, and a multi-core CPU speeds up processing meaningfully. There is no paid tier, cloud-hosted version, or subscription; LibrePhotos is entirely free, and the only ongoing cost is whatever server or NAS hardware an operator runs it on. Its target audience is privacy-conscious individuals, families, and self-hosting enthusiasts who want Google Photos-style automatic organization, search, and face grouping without uploading personal photos to a third-party cloud service. Direct competitors include other self-hosted photo platforms such as Immich, PhotoPrism, and Nextcloud's Memories app, as well as commercial services like Google Photos, Apple Photos, and Amazon Photos; LibrePhotos differentiates itself with a particularly rich local AI feature set (captioning, semantic search, scene classification) built on open models, though projects like Immich have gained significant momentum in the same self-hosted-photos category and are frequently compared against it. The main tradeoff for adopters is the need for reasonably capable self-hosted hardware to run the ML pipelines smoothly and the general operational responsibility that comes with any self-hosted service, including backups, updates, and storage planning as a photo library grows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd62c6f08-582d-469d-a2bc-f3b5a26a0454';

