-- ── LibreSign ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LibreSign is an open-source electronic signature solution, best known as a Nextcloud app, developed by the LibreCode cooperative since 2020.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Portuguese$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$LibreSign Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LibreSign review 2026: an open-source e-signature app for Nextcloud built by the LibreCode cooperative. See features, compliance, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LibreSign is an open-source electronic signature and document-signing platform, most widely known as an app for the Nextcloud self-hosted collaboration suite, though it also offers standalone and API-based deployment options. It has been developed since 2020 by LibreCode, a Brazilian worker cooperative (organized under the Somos.Coop cooperative structure) rather than a traditional venture-funded company, which shapes both its governance and its emphasis on data sovereignty and community ownership. The project is published under the AGPL-3.0 license, meaning its full source code is available for audit and modification, and any organization that runs a modified version of LibreSign as a network service must also release its changes, keeping the software permanently open. LibreSign's technical foundation relies on established cryptographic standards rather than a proprietary signing format: it uses OpenSSL for cryptographic operations and supports X.509 digital certificates, the same certificate standard used in TLS and other PKI systems, which lets signatures be validated independently of LibreSign itself. This grounding in open standards allows LibreSign to align with international electronic signature frameworks including eIDAS (the European Union's electronic identification and trust services regulation), UETA and ESIGN (the primary US electronic signature laws), and Brazil's LGPD data protection law, making it usable by organizations operating under any of these jurisdictions rather than being tied to one country's compliance regime. Functionally, LibreSign lets users upload documents, define one or more signers, and route the document through a signing workflow that supports both personal digital certificates and system-generated certificates for users who do not already have their own. It includes an envelope feature that lets multiple documents be grouped and signed together by the same set of signers in one workflow, DocMDP support that cryptographically locks a PDF against further modification once signed, QR-code-based validation that lets anyone scan a signed document to instantly verify its authenticity against the LibreSign server, automated signer reminders, and real-time tracking of where a document stands in its signing workflow. Because it is built as a first-class Nextcloud app, LibreSign integrates directly into an organization's existing Nextcloud files, folders, and permission structure, meaning a business already self-hosting Nextcloud for file storage and collaboration can add legally-relevant e-signature workflows without introducing a separate third-party SaaS tool or sending documents outside its own infrastructure; this is the core differentiation from cloud-only competitors like DocuSign, Adobe Sign, and HelloSign (Dropbox Sign), all of which require documents to pass through the vendor's cloud. LibreSign's pricing follows a freemium-style structure: the open-source core is free to self-host indefinitely within Nextcloud or standalone, while LibreCode also offers commercial services, including managed hosting and support plans, for organizations that want a turnkey deployment or professional support relationship rather than operating the infrastructure themselves; exact commercial pricing is set directly through LibreCode rather than published as fixed public tiers. The project reports hundreds of thousands of downloads and a growing base of contributors, reflecting adoption particularly among the broader Nextcloud ecosystem of privacy- and sovereignty-focused organizations. Its target audience includes public-sector agencies that need auditable, self-hosted signing workflows for transparency and compliance reasons, legal and professional services firms that require document integrity guarantees, small and medium businesses looking to avoid recurring SaaS e-signature fees, and cooperatives or NGOs whose governance model aligns with LibreCode's own cooperative structure. Competitively, LibreSign sits in the open-source and privacy-first corner of the e-signature market, distinguished from commercial leaders like DocuSign and Adobe Sign by its self-hosted, auditable, non-proprietary approach, and from other open-source signing tools by its deep, native Nextcloud integration, which is a significant advantage for the large existing base of Nextcloud self-hosters.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd5f8979c-0034-41d0-8a61-d04ac685524e';

